import { Slider as SliderPrimitive } from '@base-ui/react/slider';
import {
  Children,
  Fragment,
  forwardRef,
  isValidElement,
  type ComponentRef,
  type ForwardedRef,
  type ReactElement,
  type ReactNode,
  type RefAttributes,
} from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Slider.module.css';

type SliderValue = number | readonly number[];
type SliderChildrenParts = {
  content: ReactNode[];
  thumbs: ReactNode[];
};

type SliderRootComponent = <Value extends SliderValue = SliderValue>(
  props: SliderPrimitive.Root.Props<Value> &
    RefAttributes<ComponentRef<typeof SliderPrimitive.Root>>,
) => ReactElement;

const Slider = forwardRef(function Slider<Value extends SliderValue>(
  { children, ...props }: SliderPrimitive.Root.Props<Value>,
  ref: ForwardedRef<ComponentRef<typeof SliderPrimitive.Root>>,
) {
  const { content, thumbs } = splitSliderChildren(children);

  return (
    <SliderRoot ref={ref} {...props}>
      {content}
      <SliderControl>
        <SliderTrack>
          <SliderIndicator />
          {thumbs}
        </SliderTrack>
      </SliderControl>
    </SliderRoot>
  );
}) as SliderRootComponent;

function splitSliderChildren(children: ReactNode): SliderChildrenParts {
  const parts: SliderChildrenParts = { content: [], thumbs: [] };

  const collectChildren = (nodes: ReactNode) => {
    Children.forEach(nodes, (child) => {
      if (!isValidElement(child)) {
        parts.content.push(child);
        return;
      }

      if (isReactFragment(child)) {
        collectChildren(child.props.children);
        return;
      }

      if (isSliderThumb(child)) {
        parts.thumbs.push(child);
        return;
      }

      parts.content.push(child);
    });
  };

  collectChildren(children);

  return parts;
}

const isReactFragment = (child: ReactNode): child is ReactElement<{ children?: ReactNode }> =>
  isValidElement(child) && child.type === Fragment;

const isSliderThumb = (child: ReactNode): child is ReactElement<SliderPrimitive.Thumb.Props> =>
  isValidElement(child) && child.type === SliderThumb;

const SliderRoot = forwardRef(function SliderRoot<Value extends SliderValue>(
  { className, ...props }: SliderPrimitive.Root.Props<Value>,
  ref: ForwardedRef<ComponentRef<typeof SliderPrimitive.Root>>,
) {
  return (
    <SliderPrimitive.Root
      ref={ref}
      data-slot="slider-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
}) as SliderRootComponent;

const SliderLabel = forwardRef<
  ComponentRef<typeof SliderPrimitive.Label>,
  SliderPrimitive.Label.Props
>(function SliderLabel({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Label
      ref={ref}
      data-slot="slider-label"
      className={mergeClassName(className, styles.label)}
      {...props}
    />
  );
});

const SliderValue = forwardRef<
  ComponentRef<typeof SliderPrimitive.Value>,
  SliderPrimitive.Value.Props
>(function SliderValue({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Value
      ref={ref}
      data-slot="slider-value"
      className={mergeClassName(className, styles.value)}
      {...props}
    />
  );
});

const SliderControl = forwardRef<
  ComponentRef<typeof SliderPrimitive.Control>,
  SliderPrimitive.Control.Props
>(function SliderControl({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Control
      ref={ref}
      data-slot="slider-control"
      className={mergeClassName(className, styles.control)}
      {...props}
    />
  );
});

const SliderTrack = forwardRef<
  ComponentRef<typeof SliderPrimitive.Track>,
  SliderPrimitive.Track.Props
>(function SliderTrack({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Track
      ref={ref}
      data-slot="slider-track"
      className={mergeClassName(className, styles.track)}
      {...props}
    />
  );
});

const SliderIndicator = forwardRef<
  ComponentRef<typeof SliderPrimitive.Indicator>,
  SliderPrimitive.Indicator.Props
>(function SliderIndicator({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Indicator
      ref={ref}
      data-slot="slider-indicator"
      className={mergeClassName(className, styles.indicator)}
      {...props}
    />
  );
});

const SliderThumb = forwardRef<
  ComponentRef<typeof SliderPrimitive.Thumb>,
  SliderPrimitive.Thumb.Props
>(function SliderThumb({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Thumb
      ref={ref}
      data-slot="slider-thumb"
      className={mergeClassName(className, styles.thumb)}
      {...props}
    />
  );
});

export {
  Slider,
  SliderRoot,
  SliderLabel,
  SliderValue,
  SliderControl,
  SliderTrack,
  SliderIndicator,
  SliderThumb,
};

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    gap: var(--slider-gap, 0.5rem);
    width: var(--slider-width, 12rem);
    color: var(--slider-color, var(--color-foreground));

    &[data-orientation='vertical'] {
      grid-template-columns: 1fr;
      width: var(--slider-width-vertical, fit-content);
      justify-items: center;
    }

    &[data-disabled] {
      opacity: var(--slider-disabled-opacity, var(--opacity-disabled));
    }
  }

  .label {
    color: var(--slider-label-color, var(--slider-color, var(--color-foreground)));
    font-size: var(--slider-label-font-size, var(--text-sm));
    font-weight: var(--slider-label-font-weight, var(--weight-regular));
    line-height: var(--slider-label-line-height, var(--line-height-text-sm));
  }

  .value {
    justify-self: end;
    color: var(--slider-value-color, var(--slider-color, var(--color-foreground)));
    font-size: var(--slider-value-font-size, var(--text-sm));
    font-weight: var(--slider-value-font-weight, var(--weight-regular));
    line-height: var(--slider-value-line-height, var(--line-height-text-sm));
    text-align: right;

    &[data-orientation='vertical'] {
      justify-self: center;
      text-align: center;
    }
  }

  .control {
    grid-column: 1 / -1;
    box-sizing: border-box;
    display: flex;
    align-items: center;
    width: 100%;
    padding-block: var(--slider-control-padding-y, 0.625rem);
    touch-action: none;
    user-select: none;
    cursor: pointer;

    &[data-orientation='vertical'] {
      width: auto;
      height: var(--slider-height, 12rem);
      padding-block: 0;
      padding-inline: var(--slider-control-padding-x, 0.625rem);
      justify-content: center;
    }

    &[data-disabled] {
      cursor: default;
    }
  }

  .track {
    position: relative;
    width: 100%;
    height: var(--slider-track-size, 0.375rem);
    border-radius: var(--slider-track-radius, var(--radius-full));
    background-color: var(--slider-track-bg, var(--color-muted));
    box-shadow: inset 0 0 0 var(--slider-track-border-width, var(--border-width-sm))
      var(--slider-track-border-color, var(--color-border));
    user-select: none;

    &[data-orientation='vertical'] {
      width: var(--slider-track-size, 0.375rem);
      height: 100%;
    }
  }

  .indicator {
    border-radius: var(--slider-indicator-radius, inherit);
    background-color: var(--slider-indicator-bg, var(--color-primary));
  }

  .thumb {
    box-sizing: border-box;
    width: var(--slider-thumb-size, 1rem);
    height: var(--slider-thumb-size, 1rem);
    border: var(--slider-thumb-border-width, var(--border-width-sm)) solid
      var(--slider-thumb-border-color, var(--color-border));
    border-radius: var(--slider-thumb-radius, var(--radius-full));
    background-color: var(--slider-thumb-bg, var(--color-background));
    box-shadow: var(--slider-thumb-shadow, var(--shadow-sm));
    outline: 0;
    user-select: none;
    transition:
      border-color var(--slider-transition, var(--transition-default)),
      background-color var(--slider-transition, var(--transition-default)),
      box-shadow var(--slider-transition, var(--transition-default));

    &:has(:focus-visible) {
      border-color: var(--slider-focus-ring-color, var(--color-ring));
      box-shadow: 0 0 0 var(--border-width-sm) var(--slider-focus-ring-color, var(--color-ring));
    }

    &[data-dragging] {
      box-shadow: var(--slider-thumb-shadow-dragging, var(--shadow-md));
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }
}

export {
  Slider,
  SliderRoot,
  SliderLabel,
  SliderValue,
  SliderControl,
  SliderTrack,
  SliderIndicator,
  SliderThumb,
} from './Slider';
